mapper.select:
SELECT * FROM ( SELECT c.id AS chunk_id, c.document_id, c.category_id, c.chunk_index, c.content, c.source_title, VECTOR_DISTANCE(c.embedding, TO_VECTOR(#{queryVectorLiteral}), COSINE) AS distance, 1 - VECTOR_DISTANCE(c.embedding, TO_VECTOR(#{queryVectorLiteral}), COSINE) AS similarity FROM kb_chunk c JOIN kb_document d ON d.id = c.document_id WHERE c.enabled = 1 AND d.enabled = 1 AND d.deleted = 0 AND d.parse_status = 'PARSE_SUCCESS'
AND c.category_id = #{categoryId}
) WHERE similarity >= #{minSimilarity} ORDER BY distance FETCH FIRST #{limit} ROWS ONLY
